var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와~ 바닐라 아이스크림도 남아 있고, 살 만한 세계네.","JPN":"おお～バニラアイスも残ってるし、なかなかステキな世界ですね。","ENG":"Wow, vanilla ice cream! This world is still livable!","TWN":"哇～竟然還有香草冰淇淋，這世界真值得住下來。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"다섯 살 이후로 못 먹어 봤는데.","JPN":"5歳以降、食べられなかったのに。","ENG":"I haven't eaten this since I was five.","TWN":"我從五歲之後就再也沒吃過了。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"군 보급품 특유의 공산품스러운 맛이 나긴 하지만......","JPN":"軍隊の補給品ならではの、人工的な味はしますけど……","ENG":"It has that plasticky aftertaste that all military rations have, but...","TWN":"雖然軍隊的補給品總有股工業製品的味道，不過……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"음! 그래도 아주 달콤해!","JPN":"うん！　それでも、あま～い！","ENG":"Mm, mm! It's still yummy!","TWN":"嗯！還是很甜！"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침식체들을 막으라고 보냈더니 혼자서 뭘 노닥거리고 있는 겁니까!","JPN":"侵食体への対抗を頼んだはずなのに、何を一人でのんびりしてるんですか！","ENG":"I sent you there to stop the C.O.s. What are you doing instead?","TWN":"我派妳去阻止侵蝕體，結果妳自己一個人在那邊嗨什麼！"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"걱정 마세요. 방어선은 확실하게 지키고 있답니다.","JPN":"心配無用ですよ。防御線はかたく守っていますから。","ENG":"Don't worry. I haven't forgotten about our defense line here.","TWN":"請不要擔心。我有好好守著防線喔。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양은 에어컨 바람 쐬는 동안 저는 땡볕 아래서 고생하는데, 아이스크림 정도는 괜찮잖아요?","JPN":"カリンさんがエアコンの風にあたっている間、私は炎天下で苦労してるんですから、アイスくらい別にいいじゃないですか？","ENG":"I'm out in the sun sweating while you're indoors enjoying cool, air-conditioned air. I thought I could eat some ice cream.","TWN":"而且卡琳小姐自己吹著冷氣，我卻頂著烈日在工作，吃個冰淇淋不過分吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 혹시 혼자 먹어서 삐졌어요? 한 통 갖다 드릴까요?","JPN":"あ、もしかして、私が一人で食べてて拗ねちゃったとか？　一個、あげましょうか？","ENG":"Oh, are you upset because I'm eating it alone? Want me to get you a carton?","TWN":"啊，還是因為就我有冰淇淋吃妳不高興了？要我幫妳帶一個過去嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"필요 없습니다!","JPN":"いりません！","ENG":"No, thank you!","TWN":"不需要！"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그보다 이제부터 차원 통로 연결을 시작할 겁니다.","JPN":"それより、これから次元間通路への接続を開始します。","ENG":"By the way, I'm going to establish a dimensional passage from now on.","TWN":"現在馬上就要開始連接次元通道了。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"도중에 침식체들이 난입했다간 파장이 흐트러져서 임무가 실패로 돌아갈 수 있어요.","JPN":"途中で侵食体たちに乱入されたら、波長が乱れて任務が失敗に終わるかもしれません。","ENG":"And I can't have C.O.s interfering with the frequency, or our mission will fail.","TWN":"如果途中有侵蝕體入侵，有可能會擾亂波長，導致任務失敗。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 더 이상의 다이브는 우리 힘으로 불가능해요.","JPN":"これ以上のダイブは、私たちの力では不可能です。","ENG":"We can't dive any deeper on our own.","TWN":"現在憑我們的力量無法再進行躍入。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"억지로 시도했다간 둘 다 차원의 미아가 되고, 임무는 중단되어 버리겠죠.","JPN":"強引に進めたら、二人とも次元の間で迷子になり、任務は中止になるでしょうね。","ENG":"If we force it, we will get lost in some unknown dimension before we accomplish our mission.","TWN":"如果強行嘗試躍入，我們兩個都會迷失在次元中，任務就終止了。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까...... 그러니까 여기서......","JPN":"ですから……ですから、ここで……","ENG":"So... So, we must...","TWN":"所以……所以這裡……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......여기서, 반드시 끝을 내야 해요.","JPN":"……ここで、必ず決着をつけないと。","ENG":"We must finish it right here and now.","TWN":"……我們必須結束它。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 아이스크림 따위에 정신 팔지 말고 방어선을 유지하는 데 집중하세요.","JPN":"だから、アイスなんかに気を取られてる場合じゃありません。防御線の維持に集中してください。","ENG":"So, forget the ice cream and focus on maintaining the defense line.","TWN":"所以請不要因為一個區區冰淇淋分心，專注維持防線。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알겠습니까?","JPN":"いいですね？","ENG":"Get it?","TWN":"懂了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨? 왜 대답이 없죠? 또 제 얘기가 듣기 싫다고 자는 척하는 건가요?","JPN":"シノンさん？　どうして答えないんですか？　また真面目に聞かずに、寝てるフリでもしてるんですか？","ENG":"Shiyoung? Why aren't you answering me? Are you pretending to sleep again because you don't want to hear me?","TWN":"時雨小姐？為什麼不回答？又在裝睡嗎，這麼不想聽我的話？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 미안해요. 카린 양. 손님이 온 것 같아요.","JPN":"あ、ごめんなさい、カリンさん。お客さんが来てるみたいです。","ENG":"Oh, I'm sorry, Karin, but I think I've got company.","TWN":"啊，對不起。卡琳小姐，好像有客人來了。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"손님? 시설에서 부른 지원군인가요?","JPN":"お客さん？　施設から要請した援軍ですか？","ENG":"Company? Are they reinforcements from the base?","TWN":"客人？是設施呼叫的援軍嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"글쎄요......","JPN":"どうでしょう……","ENG":"I don't know.","TWN":"這個……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"잘은 몰라도 여유 부릴 만한 상대가 아닌 것 같네요.","JPN":"よくわかりませんが、そう簡単な相手ではなさそうです。","ENG":"I'm not sure, but they're not easy to deal with.","TWN":"雖然不太清楚，但似乎不是能從容應付的對手呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐가 됐든 빨리 끝내세요. 제 느낌상 오래 버티진 못할 것 같거든요.","JPN":"とにかく早く済ませてください。私の勘だと、そう長くは持ちこたえられないので。","ENG":"You'd better finish whatever you're doing quickly. I don't think I can hold them off for too long.","TWN":"總之，請快點結束吧。我感覺自己撐不了太久。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 통신 끊습니다.","JPN":"では、通信を切りますね。","ENG":"Now, over and out.","TWN":"那我就結束通訊了。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨? 주시영 씨?","JPN":"シノンさん？　アキヤマ・シノンさん？","ENG":"Shiyoung? Joo Shiyoung!","TWN":"時雨小姐？時雨小姐？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저, 스승님...... 제가 스승님께 이런 부탁을 드릴 줄은 몰랐는데......","JPN":"あの、師匠……僕が師匠にこんなことを願い出るなんて、心外ですが……","ENG":"Erm, Master. I never thought I'd ask you something like this, but...","TWN":"那個，師父……沒想到我會向師父提出這種請求……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"죄송하지만 제 뺨 좀 한 대 쳐 주시겠어요?","JPN":"すみませんが、僕のことを一発ひっぱたいてくれませんか？","ENG":"Could you slap me in the face once?","TWN":"不好意思，妳能賞我一巴掌嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 헛것을 보고 있는 것 같거든요.","JPN":"どうも幻覚を見ているみたいです。","ENG":"I think I'm seeing things.","TWN":"我好像看到了幻覺。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정말 매력적인 제안이다만 소용없을 것 같군.","JPN":"実に魅力的な提案だが、その必要はなさそうだな。","ENG":"That's tempting, but I don't think it's necessary.","TWN":"雖然你的請求很吸引人，但似乎沒什麼用。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......그 헛것이 내 눈에도 아주 잘 보이거든.","JPN":"……その幻覚、私の目にもバッチリ映っているからな。","ENG":"I can see what you're seeing very clearly.","TWN":"……因為這個荒謬的場景，我也看得很清楚。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐응~ 혹시나 했는데 정말 절 닮은 사람도 있었네요.","JPN":"ふーん、まさかとは思いましたけど、本当に私に似てる人もいるんですね。","ENG":"Hm, so there's also a likeness of me, just like I thought."},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여긴 대체 어떻게 되어먹은 세계람? 말로만 듣던 평행세계 같은 건가?","JPN":"ここはいったいどういう世界なの？　いわゆるパラレルワールドみたいなもの？","ENG":"What kind of world is this? A parallel universe that I've only heard about?","TWN":"這個世界到底怎麼回事啊？難道是傳說中的平行世界？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"짚고 넘어갈 게 한두 개가 아니지만...... 일단 이것 하나는 확실히 해 두죠.","JPN":"突っ込みたいところが多すぎて参りましたが……これだけはハッキリさせておきましょう。","ENG":"There are many things that I'd like to clarify, but first, let me get this straight:","TWN":"雖然現在問題很多……不過有一件事是能確定的。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"당신이 절 닮은 겁니다. 제가 당신을 닮은 게 아니라.","JPN":"あなたが僕に似てるんです。僕があなたに似てるんじゃなくてね。","ENG":"You look like me, not the other way round.","TWN":"是妳長得像我，不是我長得像妳。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어머, 그렇게 안 봤는데 자의식이 꽤 강한 아이인가 보네. 귀여워라.","JPN":"あら、案外自意識過剰な子ね、可愛いこと。","ENG":"Oh, so you're more confident than you look. How cute!","TWN":"哎呀，沒想到你是個自我意識很強的孩子呢，真可愛。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하긴, 예전부터 철없는 남동생이 하나 있어도 좋겠다 싶었어.","JPN":"まあ、世間知らずな弟が一人いても良いかもって、前から思ってたのよね。","ENG":"I've always wanted a spunky little brother like you.","TWN":"說起來，以前我就覺得，有個不懂事的弟弟也很不錯呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어때? 오늘부터 내 동생 할래?","JPN":"どう？　今日から私の弟になる気はない？","ENG":"Say, how'd you like to be my brother from now on?","TWN":"怎麼樣？從今天開始當我的弟弟吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"단호히 거절하겠습니다.","JPN":"断固お断りします。","ENG":"No, sorry.","TWN":"請容我嚴正拒絕。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"쌍둥이도 아니면서 기분 나쁠 만큼 닮은 의누나 같은 건 필요없거든요.","JPN":"双子でもないのに、気持ち悪いほど瓜二つなニセお姉さんなんて要りませんから。","ENG":"I don't want a sister who looks creepily like, me even though we're not twins.","TWN":"明明不是雙胞胎卻相似到令人不爽，我可不需要這種姐姐。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"음음, 그래, 그거야. 그런 쌀쌀한 말투가 마음에 들어.","JPN":"おお、それよそれ。その冷たく突き放すような言い方、気に入ったよ。","ENG":"Mm, mm. Yes, that's it. I like the cold tone of your voice.","TWN":"嗯嗯，很好，就是這樣。我很中意你那冷淡的語氣喔。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이렇게 만난 것도 인연인데 이 누나가 선물이라도 줘야겠지?","JPN":"これも何かの縁だし、お姉ちゃんから何かプレゼントでもあげなきゃね？","ENG":"It has to be an act of providence that we met. I'd better give you a gift.","TWN":"能這樣邂逅也是種緣分，要不要姐姐送你個禮物呀？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여기 바닐라 아이스크림 먹을래?","JPN":"このバニラアイスはどう？","ENG":"Want some vanilla ice cream?","TWN":"你想嘗一口這裡的香草冰淇淋嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"내가 먹던 거긴 한데, 그래도 아주 맛있어.","JPN":"私の食べかけだけど、とっても美味しいよ？","ENG":"I ate some of it, but there's still plenty.","TWN":"雖然我已經吃過了，但還是很好吃喔。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 아이스크림이라면 치 떨리게 싫어합니다!","JPN":"僕はアイスなんて死ぬほど嫌いですから！","ENG":"I hate ice cream with a passion!","TWN":"我恨死冰淇淋了！"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐응~ 내 입맛에 맞는 걸 보니까 너도 좋아할 것 같은데......","JPN":"ふーん、私は好きだから、君もきっと気に入ると思うけどね……","ENG":"Hm, but seeing that it tastes good to me, I think you'll like it, too."},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"설마 일부러 싫은 척 하는 건 아니겠지, 동생?","JPN":"まさか、わざと嫌いなフリしてるんじゃないよね、弟くん？","ENG":"You're not pretending to hate it, are you, little brother?","TWN":"你不會是故意裝作討厭的樣子吧，弟弟？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전혀요.","JPN":"全然。","ENG":"I am not.","TWN":"怎麼可能。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 다시 말하지만 전 당신 동생이 아닙니다.","JPN":"それに、もう一度言わせてもらいますが、僕はあなたの弟じゃありません。","ENG":"And again, I'm not your little brother.","TWN":"然後再說一遍，我不是妳弟弟。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 오빠로 할래? 난 그쪽도 별로 상관없는데.","JPN":"じゃあ、お兄ちゃんにする？　私はそっちでも構わないけど。","ENG":"Then, do you want to be my big brother? I don't care either way.","TWN":"那你想當哥哥嗎？我是無所謂啦。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그것도 싫거든요!","JPN":"それもイヤですから！","ENG":"No!","TWN":"這個也很討厭！"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......이 세상에 주시윤이 두 명이나 존재하다니 악몽이 따로 없군.","JPN":"……世界にアキヤマ・シリュウが二人もいるなんて、悪夢そのものだな。","ENG":"Two Joo Shiyoons in the same world. This is a nightmare.","TWN":"……一個世界竟然會有兩個周時雲，真是場噩夢。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"두통이 두 배로 오는 것 같아......","JPN":"頭痛も倍になりそうだ……","ENG":"I feel like I'm getting a double headache…","TWN":"我覺得我的頭痛要變成兩倍痛了……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이봐. 우린 갈 길이 바쁘다.","JPN":"おい、私たちは急いでるんだ。","ENG":"Hey, we have a place to go.","TWN":"喂，我們急著趕路。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"싸울 생각 없다면 길을 비켜 주면 좋겠군.","JPN":"戦う気がないなら、道を開けてほしいのだが。","ENG":"If you don't want to fight, then let us pass.","TWN":"如果妳不想戰鬥的話，那就把路讓開。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 그래요?","JPN":"あ、そうなんですか？","ENG":"Oh, really?","TWN":"哦，是嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"동생이 생긴 기념으로 부탁을 들어드리고 싶은 마음은 굴뚝 같긴 한데.......","JPN":"弟ができた記念に、そうしてあげたい気持ちは山々ですが……","ENG":"I'm so happy to have a brother that I'd love to let you do that,","TWN":"為了紀念有了個弟弟，我是很想聽一下妳的請求啦……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아쉽게도 제 임무는 여기서 외부인을 막는 거라서요.","JPN":"残念ながら、私の任務はここで外部からの進入を防ぐことなので。","ENG":"but unfortunately I'm here to stop all strangers.","TWN":"不過遺憾的是，我的任務就是在這裡擋下外來者。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐, 그리 오래 걸리진 않을 거에요.","JPN":"まあ、そう長くはかからないはずですけどね。","ENG":"Well, but only for a little while.","TWN":"嗯，也不會花太長時間。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"조금만 기다려 주시면 평화적으로 해결할 수 있을 전망인데 어떠세요?","JPN":"もう少し待ってもらえたら、穏便に解決できる見込みですが、いかがでしょう？","ENG":"If you could just wait for the time being, things will go between us peacefully. What do you say?","TWN":"只要你們願意稍等一下，我們就可以和平解決，怎麼樣？"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"미안하지만 이쪽도 용무가 바빠서. 기다려 줄 여유는 없군.","JPN":"悪いが、こっちも急いでるんだ。待ってる暇はない。","ENG":"I'm sorry, but we don't have the time.","TWN":"很抱歉，我們這邊也有事要忙，沒時間等妳。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"비키지 않겠다면 힘으로 뚫고 가겠다.","JPN":"道を開けないなら、力尽くで突破するのみだ。","ENG":"Let us pass, or we'll go through you.","TWN":"妳不讓開的話，我們就要用武力強行突破了。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 그거 유감이네요.","JPN":"ハハ、それは残念ですね。","ENG":"Hah hah, I'm sorry to hear that.","TWN":"哈哈，真是遺憾呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 저도 최선을 다해 적당~히 막아 보겠습니다.","JPN":"でしたら、私も最善をつくして、テキトーに対抗しますね。","ENG":"Then I'll try my best to stop you in a mediocre manner."},"stage":{"bg":"COUNTRYROAD","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};